module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);

reg [2:0] cnt;
reg [7:0] dout_parallel_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 3'b000;
    end else begin
        if (din_valid) begin
            cnt <= cnt + 3'b001;
        end else begin
            cnt <= cnt;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_valid_reg <= 1'b0;
    end else begin
        if (din_valid && cnt == 3'b111) begin
            dout_valid_reg <= 1'b1;
        end else begin
            dout_valid_reg <= 1'b0;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_parallel_reg <= 8'b00000000;
    end else begin
        if (din_valid && cnt == 3'b111) begin
            dout_parallel_reg <= {din_serial, dout_parallel_reg[7:1]};
        end else begin
            dout_parallel_reg <= dout_parallel_reg;
        end
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        dout_parallel <= 8'b00000000;
        dout_valid <= 1'b0;
    end else begin
        if (din_valid && cnt == 3'b111) begin
            dout_parallel <= {din_serial, dout_parallel_reg[7:1]};
            dout_valid <= 1'b1;
        end else begin
            dout_parallel <= dout_parallel_reg;
            dout_valid <= 1'b0;
        end
    end
end

endmodule
